import{_ as e,o as a,c as l,a3 as o}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"📚 Agent 集成","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/knowledge-base/agent-integration.md","filePath":"user-guide/tools/knowledge-base/agent-integration.md","lastUpdated":1779183599000}'),n={name:"user-guide/tools/knowledge-base/agent-integration.md"};function i(s,t,r,d,c,h){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="📚-agent-集成" tabindex="-1">📚 Agent 集成 <a class="header-anchor" href="#📚-agent-集成" aria-label="Permalink to &quot;📚 Agent 集成&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>知识库的集成并非简单的“让 Agent 自己去搜”，而是通过 <strong>上下文管道（Context Pipeline）</strong> 机制实现的。系统通过识别消息中的 <strong>占位符（Placeholder）</strong>，在消息发送给 AI 之前自动执行检索、重构和注入操作。</p><p>这种设计允许你通过 Prompt 精确控制知识的获取时机、范围和方式，实现高度可定制的 RAG 流程。</p><h2 id="核心-占位符系统" tabindex="-1">核心：占位符系统 <a class="header-anchor" href="#核心-占位符系统" aria-label="Permalink to &quot;核心：占位符系统&quot;">​</a></h2><p>在 LLM Chat 的 <strong>系统提示词（System Prompt）</strong>、<strong>Agent 模板</strong> 或 <strong>用户消息</strong> 中，你可以使用特定的占位符来触发知识库检索。</p><h3 id="基础语法" tabindex="-1">基础语法 <a class="header-anchor" href="#基础语法" aria-label="Permalink to &quot;基础语法&quot;">​</a></h3><p><code>【kb】</code> 或 <code>【knowledge】</code></p><p>当系统在消息中发现该占位符时，<code>KnowledgeProcessor</code> 会介入，根据当前对话上下文执行检索，并将占位符替换为格式化后的知识条目。</p><h3 id="进阶语法-链式参数" tabindex="-1">进阶语法（链式参数） <a class="header-anchor" href="#进阶语法-链式参数" aria-label="Permalink to &quot;进阶语法（链式参数）&quot;">​</a></h3><p>你可以通过双冒号 <code>::</code> 传递详细参数来精细控制检索行为： <code>【kb::名称::数量::阈值::模式::模式参数::引擎】</code></p><table tabindex="0"><thead><tr><th style="text-align:left;">参数位置</th><th style="text-align:left;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>名称</strong></td><td style="text-align:left;">指定知识库名称（为空则检索所有已绑定库）</td><td style="text-align:left;"><code>技术文档</code></td></tr><tr><td style="text-align:left;"><strong>数量</strong></td><td style="text-align:left;">召回条目上限（Limit）</td><td style="text-align:left;"><code>5</code></td></tr><tr><td style="text-align:left;"><strong>阈值</strong></td><td style="text-align:left;">最低相关度分数（0.0 ~ 1.0）</td><td style="text-align:left;"><code>0.45</code></td></tr><tr><td style="text-align:left;"><strong>模式</strong></td><td style="text-align:left;">激活模式（always/gate/turn/static）</td><td style="text-align:left;"><code>gate</code></td></tr><tr><td style="text-align:left;"><strong>模式参数</strong></td><td style="text-align:left;">对应模式的特定参数（如关键词、轮次等）</td><td style="text-align:left;"><code>Vue,响应式</code></td></tr><tr><td style="text-align:left;"><strong>引擎</strong></td><td style="text-align:left;">指定检索引擎 ID</td><td style="text-align:left;"><code>lens</code></td></tr></tbody></table><p><strong>示例：</strong></p><ul><li><code>【kb::我的笔记::3】</code>：从“我的笔记”库中检索前 3 条相关内容。</li><li><code>【kb::::5::0.3::gate::代码,报错】</code>：当对话中出现“代码”或“报错”时，从所有库检索前 5 条。</li></ul><hr><h2 id="激活模式-activation-modes" tabindex="-1">激活模式（Activation Modes） <a class="header-anchor" href="#激活模式-activation-modes" aria-label="Permalink to &quot;激活模式（Activation Modes）&quot;">​</a></h2><p>知识库处理器支持多种激活模式，避免无效检索消耗 Token：</p><h3 id="_1-总是激活-always" tabindex="-1">1. 总是激活 (<code>always</code>) <a class="header-anchor" href="#_1-总是激活-always" aria-label="Permalink to &quot;1. 总是激活 (`always`)&quot;">​</a></h3><ul><li><strong>语法</strong>：<code>【kb】</code> 或 <code>【kb:::::always】</code></li><li><strong>行为</strong>：每一轮对话都会执行检索。适合需要 AI 深度依赖知识库的场景。</li></ul><h3 id="_2-静态加载-static" tabindex="-1">2. 静态加载 (<code>static</code>) <a class="header-anchor" href="#_2-静态加载-static" aria-label="Permalink to &quot;2. 静态加载 (`static`)&quot;">​</a></h3><ul><li><strong>语法</strong>：<code>【kb:::::static::all】</code> 或 <code>【kb:::::static::ID1,ID2】</code></li><li><strong>行为</strong>： <ul><li><code>all</code>：直接加载指定库的所有已启用条目。</li><li><code>ID列表</code>：加载特定的知识条目。</li></ul></li><li><strong>场景</strong>：将知识库作为“固定上下文”注入，不随对话内容变化。</li></ul><h3 id="_3-轮次触发-turn" tabindex="-1">3. 轮次触发 (<code>turn</code>) <a class="header-anchor" href="#_3-轮次触发-turn" aria-label="Permalink to &quot;3. 轮次触发 (`turn`)&quot;">​</a></h3><ul><li><strong>语法</strong>：<code>【kb:::::turn::3】</code></li><li><strong>行为</strong>：每隔 N 轮对话触发一次检索。</li><li><strong>场景</strong>：减少频繁检索带来的上下文冗余。</li></ul><h3 id="_4-门控触发-gate" tabindex="-1">4. 门控触发 (<code>gate</code>) <a class="header-anchor" href="#_4-门控触发-gate" aria-label="Permalink to &quot;4. 门控触发 (`gate`)&quot;">​</a></h3><ul><li><strong>语法</strong>：<code>【kb:::::gate::关键词1,关键词2】</code></li><li><strong>行为</strong>：扫描最近几轮对话，只有出现指定关键词时才激活检索。</li><li><strong>场景</strong>：按需检索，只有聊到特定话题时才查资料。</li></ul><hr><h2 id="检索增强流程-rag-pipeline" tabindex="-1">检索增强流程（RAG Pipeline） <a class="header-anchor" href="#检索增强流程-rag-pipeline" aria-label="Permalink to &quot;检索增强流程（RAG Pipeline）&quot;">​</a></h2><p>当占位符被激活后，系统会执行以下自动化流程：</p><ol><li><strong>查询构建</strong>：取最近 N 轮对话，分别提取用户消息和 AI 回复，通过向量空间加权融合（用户文本权重较高）构建检索向量，提供丰富的语义上下文。</li><li><strong>查询预处理</strong>：对用户文本进行清洗、分词、停用词过滤，并尝试在全局标签池中进行语义匹配。</li><li><strong>多路检索</strong>：根据选定的引擎（如 <code>Blender</code> 融合引擎）同时发射字面量、语义和引力信号。</li><li><strong>分数截断与过滤</strong>：低于最低分数阈值的条目直接丢弃，再按召回上限和字数上限进一步过滤。</li><li><strong>格式化注入</strong>：根据配置的模板将结果转换为 Markdown 文本，替换掉原有的占位符。</li></ol><h2 id="检索增强配置" tabindex="-1">检索增强配置 <a class="header-anchor" href="#检索增强配置" aria-label="Permalink to &quot;检索增强配置&quot;">​</a></h2><p>在 Agent 的 <strong>知识库设置</strong> 或全局设置中，你可以调整 RAG 流程的底层参数：</p><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">说明</th><th style="text-align:left;">默认值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>上下文窗口</strong></td><td style="text-align:left;">取最近 N 轮对话（User + AI），分别向量化后加权融合为检索向量</td><td style="text-align:left;"><code>1</code></td></tr><tr><td style="text-align:left;"><strong>最低分数阈值</strong></td><td style="text-align:left;">低于此分数的条目直接丢弃，这是实际的截断依据</td><td style="text-align:left;"><code>0.3</code></td></tr><tr><td style="text-align:left;"><strong>召回上限</strong></td><td style="text-align:left;">检索结果的数量上限（实际截断以分数阈值为主）</td><td style="text-align:left;"><code>5</code></td></tr><tr><td style="text-align:left;"><strong>最大召回字数</strong></td><td style="text-align:left;">注入上下文的总字符上限（0 为不限制）</td><td style="text-align:left;"><code>0</code></td></tr><tr><td style="text-align:left;"><strong>检索缓存</strong></td><td style="text-align:left;">精确文本匹配缓存，同一查询文本直接复用结果</td><td style="text-align:left;"><code>开启</code></td></tr></tbody></table><hr><h2 id="agent-工具能力-tool-calling" tabindex="-1">Agent 工具能力（Tool Calling） <a class="header-anchor" href="#agent-工具能力-tool-calling" aria-label="Permalink to &quot;Agent 工具能力（Tool Calling）&quot;">​</a></h2><p>除了自动化的占位符注入，知识库还为具备工具调用能力的 Agent 提供了直接操作接口。这主要用于 <strong>“让 AI 帮你管理知识库”</strong>。</p><h3 id="_1-知识库-基础-kbbasic" tabindex="-1">1. 知识库（基础）- <code>kbBasic</code> <a class="header-anchor" href="#_1-知识库-基础-kbbasic" aria-label="Permalink to &quot;1. 知识库（基础）- `kbBasic`&quot;">​</a></h3><p>适合所有 Agent，用于日常的显式搜索和条目维护。</p><ul><li><strong><code>searchEntries</code></strong>：显式搜索。当用户要求“帮我查一下...”时，Agent 可以调用此工具获取更精准、带序号的结果。</li><li><strong><code>upsertEntry</code></strong>：创建或更新。让 AI 帮你记笔记或整理知识。</li><li><strong><code>updateEntryContent</code></strong>：局部更新。支持精确替换条目中的特定片段。</li></ul><h3 id="_2-知识库-管理-kbadmin" tabindex="-1">2. 知识库（管理）- <code>kbAdmin</code> <a class="header-anchor" href="#_2-知识库-管理-kbadmin" aria-label="Permalink to &quot;2. 知识库（管理）- `kbAdmin`&quot;">​</a></h3><p>高权限工具，建议仅在特定管理型 Agent 中启用。</p><ul><li><strong><code>batchUpdateMetadata</code></strong>：批量修改标签、优先级或启用状态。</li><li><strong><code>deleteEntry</code></strong>：删除条目（需显式确认）。</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-ai-在聊天时没有自动查知识库怎么办" tabindex="-1">Q：AI 在聊天时没有自动查知识库怎么办？ <a class="header-anchor" href="#q-ai-在聊天时没有自动查知识库怎么办" aria-label="Permalink to &quot;Q：AI 在聊天时没有自动查知识库怎么办？&quot;">​</a></h3><ol><li><strong>检查占位符</strong>：确认你的 System Prompt 或消息中包含了 <code>【kb】</code>。</li><li><strong>检查模式</strong>：如果你使用了 <code>gate</code> 或 <code>turn</code> 模式，确认是否满足触发条件。</li><li><strong>检查绑定</strong>：确认当前会话已在右侧面板绑定了目标知识库。</li></ol><h3 id="q-为什么-ai-总是说-未检索到相关知识" tabindex="-1">Q：为什么 AI 总是说“未检索到相关知识”？ <a class="header-anchor" href="#q-为什么-ai-总是说-未检索到相关知识" aria-label="Permalink to &quot;Q：为什么 AI 总是说“未检索到相关知识”？&quot;">​</a></h3><ol><li><strong>向量化状态</strong>：确认条目已完成向量化（绿色闪电图标）。</li><li><strong>阈值过高</strong>：如果你在占位符中设置了 <code>minScore</code>，尝试调低它（例如 <code>0.3</code>）。</li><li><strong>模型一致性</strong>：确认搜索时使用的 Embedding 模型与索引时一致。</li></ol><h3 id="q-如何实现-固定参考资料" tabindex="-1">Q：如何实现“固定参考资料”？ <a class="header-anchor" href="#q-如何实现-固定参考资料" aria-label="Permalink to &quot;Q：如何实现“固定参考资料”？&quot;">​</a></h3><p>使用静态加载模式：<code>【kb::资料库名称::::static::all】</code>。这会将该库的所有内容一次性注入上下文，不再随用户提问而变化。</p><h4 id="updateentrycontent-更新条目内容" tabindex="-1">updateEntryContent（更新条目内容） <a class="header-anchor" href="#updateentrycontent-更新条目内容" aria-label="Permalink to &quot;updateEntryContent（更新条目内容）&quot;">​</a></h4><p>让 AI 帮你修改已有条目的特定内容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把刚才的 RxJS 笔记里，把&quot;Observable&quot;改成&quot;Subject&quot;，并加上&quot;多播&quot;的说明</span></span></code></pre></div><p>AI 支持两种更新模式：</p><ul><li><strong>精确替换</strong>：指定原文片段进行局部替换（至少 15 个字符以保证精度）</li><li><strong>整体替换</strong>：替换整个条目的内容、标题、标签或优先级</li></ul><p>支持 <code>dryRun</code> 模式预览变更而不实际执行。</p><p><strong>整体替换参数说明：</strong></p><ul><li><code>replaceContent</code>：替换整个条目的内容</li><li><code>replaceKey</code>：替换条目的标题</li><li><code>replaceTags</code>：替换标签</li><li><code>replacePriority</code>：替换优先级</li></ul><h3 id="知识库-管理-管理员操作" tabindex="-1">知识库（管理）- 管理员操作 <a class="header-anchor" href="#知识库-管理-管理员操作" aria-label="Permalink to &quot;知识库（管理）- 管理员操作&quot;">​</a></h3><p>用于批量管理和维护操作：</p><h4 id="listknowledgebases-列出知识库" tabindex="-1">listKnowledgeBases（列出知识库） <a class="header-anchor" href="#listknowledgebases-列出知识库" aria-label="Permalink to &quot;listKnowledgeBases（列出知识库）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>列出我所有知识库</span></span></code></pre></div><p>返回知识库列表及统计信息（条目数、向量化率等）。</p><h4 id="listentriesmetadata-查询条目元数据" tabindex="-1">listEntriesMetadata（查询条目元数据） <a class="header-anchor" href="#listentriesmetadata-查询条目元数据" aria-label="Permalink to &quot;listEntriesMetadata（查询条目元数据）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查一下&quot;技术文档&quot;知识库里有哪些关于 React 的条目</span></span></code></pre></div><p>支持按标题关键词、标签、启用状态、向量状态过滤，以及分页和排序。</p><h4 id="batchupdatemetadata-批量更新元数据" tabindex="-1">batchUpdateMetadata（批量更新元数据） <a class="header-anchor" href="#batchupdatemetadata-批量更新元数据" aria-label="Permalink to &quot;batchUpdateMetadata（批量更新元数据）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把&quot;技术文档&quot;知识库中所有关于 React 的条目都加上&quot;前端&quot;标签</span></span></code></pre></div><p>支持批量设置启用状态、优先级、添加/移除标签。单次最多 100 条。</p><h4 id="deleteentry-删除条目" tabindex="-1">deleteEntry（删除条目） <a class="header-anchor" href="#deleteentry-删除条目" aria-label="Permalink to &quot;deleteEntry（删除条目）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把第 3 条关于&quot;过时的方案&quot;的条目删掉吧，我确定</span></span></code></pre></div><p>需要显式设置 <code>confirm: true</code> 才能执行删除，防止误操作。</p><h3 id="工具调用示例" tabindex="-1">工具调用示例 <a class="header-anchor" href="#工具调用示例" aria-label="Permalink to &quot;工具调用示例&quot;">​</a></h3><p>以下是一个完整的 AI 使用知识库的场景：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：帮我整理一下今天关于 Docker 的学习笔记</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>AI：好的，我先在知识库里搜一下有没有现成的 Docker 相关内容。</span></span>\n<span class="line"><span>（调用 searchEntries → 发现已有 3 条 Docker 相关笔记）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>AI：我找到了一些已有的 Docker 笔记。我来基于今天的讨论创建一条新的综合笔记。</span></span>\n<span class="line"><span>（调用 upsertEntry → 创建新条目 &quot;Docker 学习笔记 (2024-12-15)&quot;）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>AI：已帮你创建了「Docker 学习笔记 (2024-12-15)」，包含容器网络、数据卷和 Compose 三部分内容。我顺便给这条笔记加上了 #Docker #容器化 标签，优先级设置为 120。需要我继续补充什么吗？</span></span></code></pre></div><blockquote><p>TODO: 截图 - AI 聊天中展示工具调用的执行过程和结果</p></blockquote><h2 id="配置建议" tabindex="-1">配置建议 <a class="header-anchor" href="#配置建议" aria-label="Permalink to &quot;配置建议&quot;">​</a></h2><p>为了让 AI Agent 更有效地使用知识库，推荐以下配置：</p><h3 id="embedding-模型选择" tabindex="-1">Embedding 模型选择 <a class="header-anchor" href="#embedding-模型选择" aria-label="Permalink to &quot;Embedding 模型选择&quot;">​</a></h3><ul><li>使用中等规模的 Embedding 模型以平衡效果和速度</li><li>确保模型维度已正确配置（可通过&quot;探测模型维度&quot;自动检测）</li></ul><h3 id="检索参数调优" tabindex="-1">检索参数调优 <a class="header-anchor" href="#检索参数调优" aria-label="Permalink to &quot;检索参数调优&quot;">​</a></h3><ul><li><strong>召回上限适当增加</strong>：如果 AI 回答不够准确，可以增加搜索返回的条目数</li><li><strong>最小分数阈值调整</strong>：设置适当的最小分数阈值可以过滤掉不相关的结果</li><li><strong>引擎选择</strong>： <ul><li>精确关键词匹配场景：使用 keyword（关键词引擎）</li><li>语义理解场景：使用 vector（向量引擎）</li><li>复杂语义推理：使用 lens（透镜引擎）</li></ul></li></ul><h3 id="权限考虑" tabindex="-1">权限考虑 <a class="header-anchor" href="#权限考虑" aria-label="Permalink to &quot;权限考虑&quot;">​</a></h3><ul><li><strong>kbBasic（基础）</strong>：适合在用户日常对话中自动调用，包含搜索和条目编辑功能</li><li><strong>kbAdmin（管理）</strong>：建议仅在用户明确指令下触发，包含删除和批量操作</li></ul><h2 id="常见问题-1" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题-1" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-ai-在聊天时没有自动查知识库怎么办-1" tabindex="-1">Q：AI 在聊天时没有自动查知识库怎么办？ <a class="header-anchor" href="#q-ai-在聊天时没有自动查知识库怎么办-1" aria-label="Permalink to &quot;Q：AI 在聊天时没有自动查知识库怎么办？&quot;">​</a></h3><ol><li>确认知识库已在上下文面板中正确绑定</li><li>检查绑定的知识库是否有已向量化的条目</li><li>确认 Embedding 模型配置正确</li><li>尝试在对话中明确提及&quot;帮我查一下知识库&quot;</li></ol><h3 id="q-ai-搜索到的内容不相关怎么办" tabindex="-1">Q：AI 搜索到的内容不相关怎么办？ <a class="header-anchor" href="#q-ai-搜索到的内容不相关怎么办" aria-label="Permalink to &quot;Q：AI 搜索到的内容不相关怎么办？&quot;">​</a></h3><ol><li>检查当前使用的检索引擎是否适合该场景</li><li>在知识库设置中调整&quot;最小分数阈值&quot;，过滤低相关性结果</li><li>检查条目标签是否准确，标签能显著提升语义匹配效果</li><li>确认向量化使用的 Embedding 模型与搜索时一致</li></ol><h3 id="q-ai-如何区分多个知识库" tabindex="-1">Q：AI 如何区分多个知识库？ <a class="header-anchor" href="#q-ai-如何区分多个知识库" aria-label="Permalink to &quot;Q：AI 如何区分多个知识库？&quot;">​</a></h3><p>在调用 <code>searchEntries</code> 时，可以通过 <code>kbNames</code> 参数指定具体知识库名称。如果不指定，AI 会搜索所有绑定的知识库。</p><h3 id="q-知识库条目更新后-ai-能立即看到吗" tabindex="-1">Q：知识库条目更新后 AI 能立即看到吗？ <a class="header-anchor" href="#q-知识库条目更新后-ai-能立即看到吗" aria-label="Permalink to &quot;Q：知识库条目更新后 AI 能立即看到吗？&quot;">​</a></h3><p>如果开启了自动向量化，条目更新后会重新生成向量，AI 在下次搜索时就能检索到新内容。如果没有开启自动向量化，需要手动触发向量化后 AI 才能搜索到更新后的内容。</p><h3 id="q-ai-能创建多少条目" tabindex="-1">Q：AI 能创建多少条目？ <a class="header-anchor" href="#q-ai-能创建多少条目" aria-label="Permalink to &quot;Q：AI 能创建多少条目？&quot;">​</a></h3><p>没有硬性限制。但单次 <code>upsertEntry</code> 的内容长度建议控制在 12,000 字符以内。需要记录大量内容时，建议拆分为多个条目。</p>',94)])])}const u=e(n,[["render",i]]);export{p as __pageData,u as default};
